message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of sibling-merge operations. This involves analyzing the structural differences between the initial and final trees, specifically identifying which nodes were merged and in what order to maintain valid tree properties.",
  "helpers": [
    {
      "label": "tree_structure_analyzer",
      "instructions": "Compare the initial tree and the final tree to identify the specific sets of siblings that were merged. For each node in the final tree, determine which set of nodes from the initial tree constitutes its descendants through the merge operations. Output a mapping of final-tree nodes to their corresponding initial-tree sibling groups."
    },
    {
      "label": "merge_order_validator",
      "instructions": "Given the sets of siblings identified by the analyzer, determine a valid topological ordering for the merge operations. A merge is valid if it only combines siblings under the same parent and does not violate the hierarchical structure of the final tree. Provide a sequence of operations where each operation specifies which two nodes (or a node and a group) are merged into one."
    }
  ],
  "synthesis_brief": "Combine the mapping of final nodes to initial sibling groups with the validated sequence of merge operations to produce the complete reconstruction of the sibling-merge process."
}

